INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Ideogram 3.0 text-to-image model$q$, $q$Generates photorealistic and stylized images from text prompts with strong prompt adherence and accurate in-image text rendering.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Magic Fill (inpainting)$q$, $q$Mask a specific region of an image and regenerate only that area to replace objects, fix errors or change details.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Extend (outpainting)$q$, $q$Expand an image beyond its original borders and let the model generate new, consistent content in the extended area.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Ideogram Canvas$q$, $q$An infinite editing workspace for combining, resizing and iterating on generated or uploaded images in one place.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Style References$q$, $q$Upload reference images to steer the visual style of new generations without directly copying the source.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Remix$q$, $q$Use an existing image as a structural or stylistic starting point for a new generation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Describe$q$, $q$Reverse-engineer a text prompt from an existing image for reuse or iteration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Developer API$q$, $q$REST endpoints for text-to-image generation, remix, Magic Fill editing, Extend and background replacement, billed per image.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Best-in-class accuracy for rendering legible text inside generated images$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Generous free tier for casual and occasional use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Canvas workflow makes iterative editing faster than regenerating from scratch$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Commercial usage rights included on paid plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$API pricing is usage-based, which suits developers with variable volume$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Free tier images are processed through a slower queue, which can mean noticeable wait times$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$No native mobile app; access is web-only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Team and Enterprise pricing is not fully transparent and requires contacting sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Some artistic styles are less refined than Midjourney's default aesthetic$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Credit and plan structure can be confusing to first-time users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$What is Ideogram used for?$q$, $q$Ideogram is used to generate AI images from text prompts, particularly for graphics that need accurate readable text, such as posters, ads, logos and social media creative, and to edit those images using Magic Fill and Extend.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Is Ideogram free to use?$q$, $q$Yes, Ideogram offers a free plan with roughly 25 images per day processed through a slower queue at standard resolution; paid Plus and Pro plans unlock higher resolution, faster processing and, on Pro, full commercial usage rights.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Who founded Ideogram?$q$, $q$Ideogram was founded in December 2022 by Mohammad Norouzi, William Chan, Chitwan Saharia and Jonathan Ho, former Google Brain researchers who worked on Google's Imagen model.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Can I use Ideogram images commercially?$q$, $q$Full commercial usage rights are included on the Pro plan; lower tiers may carry usage restrictions, so it is worth checking Ideogram's current terms before using free-tier images in commercial work.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Does Ideogram have an API?$q$, $q$Yes, Ideogram offers a REST API with endpoints for text-to-image generation, remix, Magic Fill inpainting, Extend outpainting and background replacement, billed per image generated.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$How is Ideogram different from Midjourney?$q$, $q$Ideogram is generally considered stronger at rendering accurate, legible text inside images and offers a web-based Canvas editing workflow, while Midjourney is often seen as producing more painterly, artistic default results through a Discord-centric workflow.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Marketing and social graphics$q$, $q$Creating ads, posters and social posts that require legible in-image text like headlines, prices or calls to action.$q$, $q$Marketers and social media creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Iterative design editing$q$, $q$Using Magic Fill and Extend inside Canvas to revise specific parts of an image without regenerating the whole composition.$q$, $q$Designers and creative agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Programmatic image generation$q$, $q$Integrating the Ideogram API into apps or pipelines that need on-demand, text-accurate image generation at scale.$q$, $q$Developers and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Roughly 25 images per day","Standard resolution","Slower processing queue"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Plus$q$, $q$$8-$10/month$q$, $q$Monthly or annual (annual is cheaper)$q$, NULL, $q$["Higher daily generation volume","Higher resolution output","Faster processing than Free"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Pro$q$, $q$$20-$24/month$q$, $q$Monthly or annual (annual is cheaper)$q$, NULL, $q$["Effectively unlimited daily generations","Priority fast-queue processing","Full commercial usage rights"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual, contact sales$q$, NULL, $q$["Team administration and centralized billing","SSO and dedicated support","Custom usage limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ideogram is a text-to-image AI platform built by a team of former Google Brain researchers who worked on Google's Imagen model. Founded in Toronto in late 2022, the company built its reputation on a specific technical problem that rival image generators struggled with for years: rendering clean, legible text inside an AI-generated image, such as a logo, poster headline or product label.$q$, $q$Beyond raw generation, Ideogram has grown into a more complete creative workspace through Ideogram Canvas, an infinite editing surface where generated and uploaded images can be combined, extended and locally edited using Magic Fill (inpainting) and Extend (outpainting). This positions Ideogram less as a novelty image generator and more as a production tool for marketing and design work that needs to be finished and shippable.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Ideogram's core model, currently Ideogram 3.0, generates photorealistic and stylized images from text prompts with a strong emphasis on prompt adherence and accurate typography. Style References let users upload reference imagery to steer the visual direction of a new generation without copying it outright, while Remix reuses an existing image's composition or style as a jumping-off point.$q$, $q$Editing tools inside Canvas, namely Magic Fill for masked inpainting and Extend for outpainting beyond an image's original borders, allow targeted revisions instead of full regenerations. A public API exposes the same generation and editing endpoints for developers who want to build image generation into their own apps or automate creative production at scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Ideogram offers a free tier with roughly 25 images per day processed through a slower queue at standard resolution, which is generous enough for casual experimentation. Paid plans start with Plus at roughly $8 to $10 per month for higher resolution and faster generation, and Pro at roughly $20 to $24 per month for effectively unlimited daily generations, priority processing and full commercial rights to use generated images.$q$, $q$Team and Enterprise options exist for organizations that need multi-seat billing, centralized administration and dedicated support, with Enterprise pricing available only on request. API usage is billed separately per image generated, ranging from a few cents up to about ten cents depending on the model and resolution selected, which suits developers who want to pay only for what they use rather than committing to a subscription tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
