INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Unlimited-device backup per account$q$, $q$Personal plans back up an unlimited number of computers, phones and external drives under a single account and storage allowance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$File versioning and snapshots$q$, $q$Keeps up to 30 days of file history and point-in-time snapshots to recover from ransomware or accidental changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Private encryption key$q$, $q$Optional user-held encryption key ensures only the account owner can decrypt backed-up data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$IDrive Express physical recovery$q$, $q$Ships a physical hard drive to speed up restoring very large backups instead of relying on a download.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Cross-platform apps$q$, $q$Native clients for Windows, Mac, iOS and Android, plus support for NAS and server backup.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$IDrive e2 object storage$q$, $q$S3-compatible cloud object storage billed at a flat rate per terabyte with no egress fees.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Team and Business account management$q$, $q$Centralized multi-user administration with per-seat licensing for organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Microsoft 365 and Google Workspace backup$q$, $q$Add-on backup coverage for cloud productivity suite data, billed per seat annually.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Very low cost per terabyte compared to many cloud backup competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Single account covers unlimited devices on personal plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Ransomware-resistant snapshots and 30-day file versioning$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Optional private encryption key for zero-knowledge style privacy$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$IDrive e2 object storage has no egress fees$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Renewal pricing after the first promotional year can be significantly higher$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Interface and desktop client feel dated compared to some competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Restoring very large backups can be slow without paying for IDrive Express$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Free tier is limited to just 10GB$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Sizing the right Team or Business plan can be confusing with so many tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Is IDrive really free?$q$, $q$IDrive offers a free Basic plan with 10GB of storage and no credit card required, but larger storage tiers require a paid Personal, Team or Business plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$What is IDrive Express?$q$, $q$IDrive Express is a physical hard-drive shipping service that lets customers receive or send their backup data on a physical drive instead of downloading or uploading it over the internet, useful for very large restores.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Is IDrive backup encrypted?$q$, $q$Yes, IDrive encrypts data in transit and at rest, and users can optionally set a private encryption key so that only they can decrypt their backed-up data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$What is IDrive e2?$q$, $q$IDrive e2 is a separate S3-compatible object storage product priced at a flat rate per terabyte with no egress fees, aimed at developers and businesses as a lower-cost alternative to Amazon S3.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$How does IDrive's pricing change after the first year?$q$, $q$New customers typically get a discounted first-year or first-two-year rate, and pricing reverts to the standard renewal rate afterward, which can be substantially higher.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$How is IDrive different from IBackup?$q$, $q$IBackup is a longer-standing, more business-oriented backup brand also owned by IDrive Inc., while IDrive is the company's primary consumer and SMB backup product.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Multi-device family backup$q$, $q$Backing up several household computers and phones under a single, affordable storage plan.$q$, $q$Individuals and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$SMB backup and disaster recovery$q$, $q$Centralized team backup with snapshots and versioning to recover from ransomware or hardware failure.$q$, $q$Small and mid-sized businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Affordable object storage for developers$q$, $q$Using IDrive e2 as a flat-rate, S3-compatible storage backend for applications or backups.$q$, $q$Developers and managed service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["10GB storage","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Personal$q$, $q$From $11.99/month (5TB)$q$, $q$Monthly or annual (promotional discounts available)$q$, NULL, $q$["Unlimited devices per account","30 days file versioning","Optional private encryption key"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Team$q$, $q$From $11.99/month (5TB, 5 users)$q$, $q$Monthly or annual$q$, NULL, $q$["Per-seat multi-user licensing","Centralized administration","Shared storage pool"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Business$q$, $q$From $59.99/month (1.25TB, unlimited users)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited user accounts","Server and NAS backup","Compliance-oriented backup options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$IDrive is a cloud backup and storage service run by IDrive Inc., a Calabasas, California company that traces its roots back to 1995 as Pro Softnet Corporation before rebranding around its flagship IDrive product in 2013. Unlike sync-first tools such as Dropbox, IDrive is built specifically as continuous, versioned backup software covering computers, external drives, NAS devices, servers and mobile photos.$q$, $q$A defining feature of IDrive's personal plans is that a single account covers an unlimited number of devices rather than charging per machine, which makes it comparatively inexpensive for households or individuals with several computers and phones. The company also operates IDrive e2, a separate S3-compatible object storage product aimed at developers, and RemotePC for remote desktop access.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core backup features include continuous incremental backup, 30 days of file versioning, and point-in-time snapshots that help recover from ransomware or accidental deletion rather than backing up an already-encrypted file over the only good copy. Users can set a private encryption key so that data is unreadable even to IDrive's own staff, and IDrive Express offers physical hard-drive shipping for restoring very large backups faster than a download would allow.$q$, $q$For businesses, IDrive supports server and NAS backup, multi-user team accounts with centralized administration, and compliance-oriented backup for Microsoft 365 and Google Workspace data. IDrive e2 extends the platform into flat-rate, S3-compatible cloud object storage with no egress fees, positioning it as a lower-cost alternative to Amazon S3 for developers and businesses storing large volumes of data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$IDrive's free Basic plan provides 10GB of storage with no credit card required, useful for testing the service before committing. Paid Personal plans scale by storage size, from 5TB at $11.99 per month up to 100TB at $119.99 per month, and new customers typically get 30 to 50 percent off their first year or two years, though renewal pricing reverts to the standard rate afterward.$q$, $q$Team and Business plans add per-seat and multi-user licensing on top of the same storage tiers, with Business plans supporting unlimited user accounts and server backup. IDrive e2 object storage is billed separately at a flat $4 per terabyte per month with no egress charges, which is simpler to budget than many usage-based cloud storage providers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
