INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Applets$q$, $q$Saved trigger-action automations connecting one service's event to one or more actions in another service.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$1,000-plus service integrations$q$, $q$A large partner catalog spanning smart-home devices, productivity apps, weather data and social platforms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Webhooks$q$, $q$Developer-facing triggers that let custom code or scripts fire an Applet from outside IFTTT's built-in service list.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Multi-action Applets$q$, $q$Trigger several actions from a single event instead of being limited to one action per trigger.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Filter code$q$, $q$JavaScript-based conditional logic on paid plans that lets an Applet only fire under specific conditions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Smart-home device triggers$q$, $q$Native integrations with popular smart-home hardware for lights, thermostats and sensors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Location and device triggers$q$, $q$Mobile app support for geofencing and device-state-based automation triggers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$AI service connections$q$, $q$Pro+ integrations that let Applets trigger or receive actions from AI-related services.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Extremely low cost of entry for basic automation$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Large library of smart-home and consumer app integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Simple, beginner-friendly no-code interface$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Mobile app supports location and device-based triggers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Webhooks enable custom, developer-built integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Free plan is capped at just 2 Applets, which is very restrictive$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Less suited to complex, multi-step business workflows than Zapier or Make$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Automations depend on third-party APIs that can change or break without notice$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Execution is not always real-time and can lag behind the triggering event$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Advanced conditional logic requires the Pro+ tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$What does IFTTT stand for?$q$, $q$IFTTT stands for If This Then That, describing how its automations pair a trigger event in one service with an action in another.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Is IFTTT free to use?$q$, $q$IFTTT has a free plan, but it is limited to just 2 active Applets; unlocking more Applets and features requires the Pro or Pro+ paid plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$What is an Applet?$q$, $q$An Applet is a saved automation on IFTTT that pairs a trigger ("this") in one service with one or more actions ("that") in another service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$What is the difference between IFTTT Pro and Pro+?$q$, $q$Pro, at $2.99 per month, allows up to 20 Applets with multi-action support and webhooks, while Pro+, at $8.99 per month, removes the Applet limit and adds filter code, AI service connections and multiple connected accounts per service.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Does IFTTT offer a free trial for paid plans?$q$, $q$Yes, both Pro and Pro+ include a 7-day free trial for users who have not already used a trial.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$What are IFTTT's main competitors?$q$, $q$Zapier, Make (formerly Integromat), Microsoft Power Automate, n8n and Home Assistant are commonly cited as alternatives, with IFTTT generally seen as the simplest and cheapest option for personal and smart-home automation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Smart home automation$q$, $q$Connecting lights, thermostats, sensors and other smart-home devices to trigger coordinated actions.$q$, $q$Homeowners and smart-home enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Personal productivity automation$q$, $q$Automating calendar updates, notifications and simple data backups between everyday apps.$q$, $q$Individual professionals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Social and marketing cross-posting$q$, $q$Automatically sharing content across social platforms or triggering marketing notifications without engineering support.$q$, $q$Creators and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 2 active Applets","Basic single-action automations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Pro$q$, $q$$2.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 20 Applets","Multi-action support","Webhooks","Faster execution"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$Pro+$q$, $q$$8.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited Applets","Filter code (JavaScript)","AI service connections","Multiple connected accounts per service"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$IFTTT is one of the earliest and best-known no-code automation platforms, launched in December 2010 by Linden Tibbets and co-founders. The name is an acronym for If This Then That, describing its core mental model: a trigger event in one app or device sets off an action in another, without any coding required.$q$, $q$Originally focused on very simple one-trigger, one-action recipes, IFTTT has broadened over time to support multi-action Applets, webhooks for developer-triggered automations, and conditional filter code on paid plans, while keeping the interface approachable for non-technical users setting up smart-home and personal productivity automations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The heart of IFTTT is the Applet, a saved automation combining a trigger service and one or more action services from IFTTT's catalog of over a thousand partners, spanning smart-home hardware, productivity apps, weather data and social platforms. Webhooks let developers fire Applets from their own code or scripts, extending IFTTT beyond its built-in partner list.$q$, $q$On paid tiers, filter code allows JavaScript-based conditional logic inside an Applet so actions only fire under specific circumstances, and Pro+ adds the ability to connect multiple accounts of the same service and to trigger actions in AI-related services, reflecting IFTTT's push into AI-assisted automation alongside its original smart-home roots.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$IFTTT's Free plan is intentionally limited to 2 active Applets, enough to try the platform but too restrictive for most ongoing use, which nudges active users toward a paid tier. Pro, at $2.99 per month, raises the cap to 20 Applets and adds multi-action support, faster execution and webhook access, making it one of the cheapest paid automation tools on the market.$q$, $q$Pro+, at $8.99 per month, removes the Applet limit entirely and unlocks filter code, AI service connections and multiple connected accounts per service. Both paid tiers can be billed monthly or annually and include a 7-day free trial for new subscribers, giving users a low-risk way to evaluate the extra capacity before committing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
