INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b595e89a-3f11-4ebc-af37-5b2c490d5f49', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$SCORM-compliant course management$q$, $q$Supports SCORM 1.2 and SCORM 2004 compliant course packages alongside native content authoring tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Assessment and testing engine$q$, $q$Question pools, randomized and timed exams, and competence-based evaluation built into the core platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Collaboration tools$q$, $q$Forums, wikis, blogs, chat and group workspaces for learner and instructor collaboration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$E-portfolio$q$, $q$Lets learners build portfolios of work and achievements over time within the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Role-based multi-tenant access control$q$, $q$Granular permissions that support deployments ranging from small departments to institutions with 100,000-plus users.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Calendar and messaging$q$, $q$Built-in scheduling and internal messaging for courses and organizational communication.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Certificate generation$q$, $q$Automated certificate issuance on course or assessment completion.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Learning analytics and reporting$q$, $q$Reporting tools for tracking learner progress and course completion across an installation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Completely free and open source under the GPL$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Full data ownership through self-hosting, well suited to GDPR compliance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Scales from small departments to installations with over 100,000 users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Robust, built-in assessment and testing engine$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Active nonprofit governance with 90-plus institutional members$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Requires PHP and MySQL server administration skills to self-host$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Interface feels dated compared to modern commercial LMS platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Smaller third-party plugin ecosystem than Moodle$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Documentation and community support skew toward German-language resources$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$No official vendor-run SaaS hosting; institutions must self-host or use a third-party provider$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Is ILIAS free to use?$q$, $q$Yes, ILIAS is released under the GNU General Public License and has no software license fee; institutions only pay for hosting infrastructure or optional managed services.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Who develops and maintains ILIAS?$q$, $q$ILIAS is developed and governed by the German nonprofit association ILIAS open source e-Learning e.V., based in Cologne, together with a global community of developers and more than 90 institutional society members.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$What does ILIAS stand for?$q$, $q$ILIAS stands for Integriertes Lern-, Informations- und Arbeitskooperations-System, German for Integrated Learning, Information and Work Cooperation System.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Can I host ILIAS myself?$q$, $q$Yes, ILIAS is designed to be self-hosted on any server supporting PHP and a MySQL-compatible database, and can also be deployed through one of the ILIAS Society's certified service providers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Is ILIAS SCORM compliant?$q$, $q$Yes, ILIAS supports SCORM 1.2 and SCORM 2004, and it became the first open-source LMS to achieve full SCORM 1.2 compliance in 2004.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$How does ILIAS compare to Moodle?$q$, $q$Both are free, open-source, self-hosted LMS platforms, but ILIAS is generally seen as offering a stronger built-in assessment engine and deeper adoption in German-speaking education, while Moodle has a larger international plugin and theming ecosystem.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$University online course delivery$q$, $q$Running large-scale online courses, assessments and exams across university departments.$q$, $q$Higher education institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Corporate learning and development$q$, $q$Operating a self-hosted, compliant training platform for employee onboarding and certification.$q$, $q$Corporate L&D departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$GDPR-conscious K-12 and vocational training$q$, $q$Delivering e-learning while keeping full control over student data on institution-owned infrastructure.$q$, $q$Schools and vocational training providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A (GPL license)$q$, NULL, $q$["Full source code access","Unlimited users on your own infrastructure","All core LMS features included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$Managed Hosting via Service Provider$q$, $q$Custom pricing$q$, $q$Set by individual certified provider$q$, NULL, $q$["Hosting and infrastructure management","Migration and customization support","Training and ongoing support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ILIAS is a free, open-source learning management system that began as a university research project at the University of Cologne in 1997 and has grown into one of the longest-running LMS platforms still in active development. Its name is a German acronym for Integrated Learning, Information and Work Cooperation System, reflecting its origins as an academic tool for course delivery and collaboration.$q$, $q$Unlike commercial SaaS LMS platforms, ILIAS is self-hosted and governed by a German nonprofit association, ILIAS open source e-Learning e.V., which coordinates development among a community of institutional members and certified service providers rather than a single company. This structure makes it especially popular among European public universities and organizations that need full control over student data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ILIAS covers the core functions expected of an enterprise LMS: SCORM-compliant course content, a flexible assessment and testing engine with randomized and timed exams, and collaboration tools such as forums, wikis, blogs and group workspaces. Its e-portfolio and certificate generation features support competence-based and continuing-education programs alongside traditional coursework.$q$, $q$Because it is self-hosted and role-based, ILIAS scales from a single department running a handful of courses to national or enterprise deployments serving well over 100,000 users, with granular permissions controlling who can create, edit or grade content across a large multi-tenant installation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ILIAS itself has no license fee; it is released under the GPL and can be downloaded, installed and modified at no cost. Institutions instead budget for the infrastructure needed to self-host it, whether that means an internal IT team or a third-party server environment.$q$, $q$Organizations that prefer not to manage hosting themselves can contract one of the ILIAS Society's roughly 17 certified service providers for managed hosting, migration, customization and training, with pricing set individually by each provider. An optional, relatively inexpensive ILIAS Society membership is also available for institutions that want direct input into the project's governance and roadmap.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bc4665f4-feb7-4c9e-a25a-245306d04d1f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
