INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Merge and split PDF$q$, $q$Combine multiple PDFs into one file or split a single PDF into separate documents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Compress PDF$q$, $q$Reduce PDF file size while preserving readable quality for easier sharing and storage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Format conversion$q$, $q$Convert PDFs to and from Word, Excel, PowerPoint, JPG and other common file formats.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$OCR text recognition$q$, $q$Turns scanned documents into searchable, editable and selectable text.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Edit, annotate and sign$q$, $q$Add text, annotations, and fill and sign forms directly inside the browser.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Password protect and unlock$q$, $q$Add or remove password protection and permissions on PDF files.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Organize and watermark pages$q$, $q$Rotate, reorder, delete and add watermarks or page numbers to PDF pages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$REST API$q$, $q$Lets developers embed iLovePDF's PDF processing tools into their own applications.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Generous free tier that covers most common PDF tasks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Fast, no-install browser-based workflow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Wide range of supported file format conversions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Premium tier is affordably priced relative to competitors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$API available for developers to embed PDF processing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Free tier limits daily operations and maximum file size$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Ads appear on the free version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Advanced editing is more basic than dedicated desktop editors like Acrobat$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Batch processing of multiple files at once is gated behind Premium$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$An account is required to access Premium features and file history$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Is iLovePDF free?$q$, $q$Yes, iLovePDF's core toolset is free to use with daily usage and file-size limits and ads; a Premium subscription removes these limits and adds OCR and batch processing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Who founded iLovePDF?$q$, $q$iLovePDF was founded in 2010 in Barcelona, Spain by Marco Grossi, who built it originally as a simple free tool for merging PDF files.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Is it safe to upload sensitive documents to iLovePDF?$q$, $q$iLovePDF processes files on its servers and states that uploaded files are deleted after processing; users with highly sensitive documents may still prefer offline or self-hosted PDF tools for extra assurance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$What does iLovePDF Premium include?$q$, $q$Premium removes ads and adds OCR, unlimited file sizes, and the ability to process multiple files simultaneously, priced at roughly $4 to $8 per month depending on billing cycle.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Does iLovePDF have a desktop or mobile app?$q$, $q$Yes, iLovePDF offers native desktop apps for Windows and Mac, mobile apps for iOS and Android, and a browser extension in addition to its main web tool.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Does iLovePDF offer an API?$q$, $q$Yes, iLovePDF provides a REST API priced on a usage basis for developers who want to integrate its PDF processing engine into their own applications.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Quick personal PDF edits$q$, $q$Merging, compressing or converting a document without installing desktop software.$q$, $q$Students and office workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Standardized business document workflows$q$, $q$Using Premium or Team accounts to compress, convert and sign documents consistently across an organization.$q$, $q$Small and mid-sized businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Embedded PDF processing$q$, $q$Integrating the iLovePDF API into a product or internal tool that needs automated PDF conversion or compression.$q$, $q$Developers and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Core PDF tools with daily usage limits","Maximum file size cap","Ad-supported"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Premium$q$, $q$$4-$8/month$q$, $q$Monthly or annual (annual is cheaper)$q$, NULL, $q$["No ads","OCR text recognition","Unlimited file size","Simultaneous batch processing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Business$q$, $q$Custom pricing$q$, $q$Annual, per seat$q$, NULL, $q$["Multi-seat licensing","Centralized billing","All Premium features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$API$q$, $q$Usage-based$q$, $q$Pay-as-you-go$q$, NULL, $q$["Programmatic access to PDF processing tools","Volume-based pricing","Documentation and developer support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$iLovePDF started in 2010 as a simple one-page website for merging PDF files, built by Barcelona-based founder Marco Grossi after he struggled to find an affordable, easy tool to do the job himself. It has since grown into a full suite of more than 25 browser-based PDF utilities used by millions of people each month.$q$, $q$The company remains privately owned and, according to its founder, bootstrapped without outside venture investment, funding its growth primarily through Premium subscriptions and advertising on its free tools. It now ranks among the most-visited software utility sites globally, competing closely with Smallpdf for the online PDF tool audience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$iLovePDF's core tools cover the everyday PDF tasks most people need: merging and splitting documents, compressing file size, converting to and from Word, Excel, PowerPoint and image formats, rotating and reorganizing pages, and adding watermarks or page numbers. Editing tools let users annotate PDFs, fill and sign forms, and redact sensitive content directly in the browser.$q$, $q$More advanced capabilities include OCR for making scanned documents searchable and editable, password protection and unlocking, comparing two versions of a PDF, and repairing corrupted files. A REST API extends the same processing engine to developers who want to build PDF handling into their own products rather than using the consumer-facing website.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The free tier covers most common tasks but limits the number of daily operations, caps file size, and shows ads, which is enough for occasional personal use. The Premium subscription, priced roughly between $4 and $8 per month depending on billing cycle, removes ads and unlocks OCR, unlimited file sizes and simultaneous batch processing of multiple files.$q$, $q$Business and Team plans add multi-seat licensing and centralized billing for organizations that need several employees using Premium features, while API pricing is billed separately based on usage volume for developers embedding iLovePDF's PDF processing engine into their own applications.$q$]::text[], 2);
