INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$70-plus supported formats$q$, $q$Handles common formats plus professional formats like PSD, HEIC, HEIF, RAW and EPS.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Local AI background removal$q$, $q$Removes image backgrounds using bundled models that run entirely on the host CPU, with no API keys or cloud calls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Bulk compression$q$, $q$Multi-core parallel processing compresses large batches of images quickly via the CLI.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Format conversion$q$, $q$Converts between supported image formats and can generate PDFs from image sets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Per-file cropping$q$, $q$Applies aspect-ratio presets to crop individual images before conversion or compression.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Single-container deployment$q$, $q$Ships as one hardened Docker image bundling all required codecs for a one-command setup.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Completely free and open source under GPL-3.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Strong privacy guarantee since images never leave your own server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Extremely broad format support including professional RAW and PSD files$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Simple one-command Docker installation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Can run fully offline and air-gapped after the initial image pull$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Requires Docker and basic self-hosting knowledge, not ideal for non-technical users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$No official cloud-hosted version for those unwilling to self-host$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Solo-maintainer project, so support depends on community and GitHub issues rather than a dedicated team$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$No mobile app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Web interface is fairly minimal compared to polished commercial compressors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Is ImgCompress free?$q$, $q$Yes, ImgCompress is completely free and open source under the GPL-3.0 license, with no paid tier or feature paywall.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Do I need Docker to use ImgCompress?$q$, $q$Yes, ImgCompress is distributed as a Docker container, so Docker (or a compatible container runtime) is required to run it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Does ImgCompress upload my images anywhere?$q$, $q$No, ImgCompress processes images entirely on the server or machine where you run its Docker container, and can operate fully offline after the initial image pull.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$What image formats does ImgCompress support?$q$, $q$ImgCompress supports more than 70 input formats, including JPEG, PNG, WebP, TIFF, BMP, PSD, HEIC, HEIF, RAW and EPS, with output to common formats or PDF.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Does ImgCompress remove image backgrounds?$q$, $q$Yes, it includes a local AI background removal feature that runs entirely on the host machine's CPU without requiring API keys or cloud services.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Who maintains ImgCompress?$q$, $q$ImgCompress is built and maintained by independent developer Karim Zouine as a solo open-source project rather than by a company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Private personal photo compression$q$, $q$Compressing and converting personal photos without uploading them to a cloud service.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Professional format batch conversion$q$, $q$Batch converting RAW, PSD or HEIC files locally as part of a photography or creative workflow.$q$, $q$Photographers and creatives$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Homelab image processing utility$q$, $q$Adding a self-hosted image compression and conversion tool to an existing Docker or NAS-based homelab stack.$q$, $q$Homelab and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A (GPL-3.0 license)$q$, NULL, $q$["Full source code access","Unlimited local use","All features including AI background removal"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$Sponsor the Project$q$, $q$Optional donation$q$, $q$One-time or recurring via PayPal$q$, NULL, $q$["Supports continued development","No additional features unlocked","Same software as the free self-hosted version"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ImgCompress is an open-source, self-hosted image-processing tool built by independent developer Karim Zouine as a privacy-respecting alternative to cloud compressors like TinyPNG. It is distributed as a single Docker container so it can be deployed with one command on a home server, NAS or small cloud VM, and the full source code is licensed under GPL-3.0 for anyone to audit, fork or modify.$q$, $q$The tool's defining principle is that images never leave the machine running it; once the Docker image has been downloaded, ImgCompress can operate entirely offline with no calls to any external API, which sets it apart from most browser-based or cloud-hosted image compression services.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ImgCompress supports over 70 input image formats, including everyday formats like JPEG, PNG and WebP alongside professional and specialist formats such as PSD, HEIC, HEIF and RAW camera files that most compression tools do not handle. It can compress images to a target size, convert between formats, generate PDFs from image sets, and crop images to preset aspect ratios before conversion.$q$, $q$A locally-run AI model handles background removal entirely on the host machine's CPU, with no API keys or cloud calls required. Both a web interface, served locally, and a command-line interface are available, with the CLI supporting multi-core parallel processing for fast, scripted batch jobs across large image libraries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ImgCompress is entirely free and open source, with no license fee, subscription, or feature paywall of any kind. Because it is self-hosted, the only real cost is the compute resources used to run the Docker container, which can be as modest as a Raspberry Pi or as substantial as a dedicated homelab server, depending on the volume of images processed.$q$, $q$The maintainer accepts optional PayPal sponsorships to support ongoing development, but sponsoring does not unlock any additional functionality, keeping the software equally free and fully featured for every user regardless of whether they choose to contribute financially.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('959b9d2f-85ba-483f-9122-54acf02a036f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Automatic mobile backup$q$, $q$iOS and Android apps back up camera-roll photos and videos to a self-hosted server in the background.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$AI facial recognition$q$, $q$Automatically groups photos by person using locally-run facial recognition models.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Semantic photo search$q$, $q$Finds photos using natural-language descriptions of their contents via CLIP-based search.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Object and scene detection$q$, $q$Identifies objects and scenes within photos to improve search and organization.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Shared albums and multi-user support$q$, $q$Supports shared family albums and multiple user accounts on one server.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$External library support$q$, $q$Imports and manages existing photo folders and RAW or Live Photo files alongside backed-up content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Map view$q$, $q$Displays photos on a map based on their embedded geolocation data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Duplicate detection$q$, $q$Identifies duplicate photos within a library to help clean up storage.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Completely free and open source with no feature paywall$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Strong feature parity with Google Photos, including AI search and face grouping$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Full data ownership through self-hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Active, fast-moving development backed by FUTO funding$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Native iOS and Android apps for seamless automatic backup$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Requires Docker and self-hosting knowledge plus your own server hardware or a VPS$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$No official managed cloud-hosted version from the core team$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Ongoing maintenance and updates are the user's own responsibility$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$AI features can be resource-intensive for large libraries without decent CPU or GPU hardware$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$The project only reached a stable v2.0 release in October 2025, so earlier versions carried stability caveats$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Is Immich really free?$q$, $q$Yes, Immich is completely free under its AGPL-3.0 open-source license with no subscription tier or feature paywall; the only cost is the hardware or hosting used to run it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Do I need to self-host Immich?$q$, $q$Yes, there is no official managed cloud version; Immich is deployed via Docker on your own server, NAS or a rented VPS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Who created Immich?$q$, $q$Immich was started in February 2022 by developer Alex Tran as a personal project, and it joined the FUTO foundation as a funded, full-time effort in May 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Does Immich support facial recognition and AI search?$q$, $q$Yes, Immich includes locally-run facial recognition and CLIP-based semantic search that let users find photos by description without manual tagging.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$What license is Immich released under?$q$, $q$Immich is released under the GNU Affero General Public License v3.0 (AGPL-3.0).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$How much does it cost to run an Immich server?$q$, $q$There is no software cost, but the self-hosting community estimates roughly $300 to $500 for a one-time home server setup plus a few dollars a month in electricity, or the cost of a cloud VM if hosted remotely.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Migrating off Google Photos$q$, $q$Families moving away from Google Photos or iCloud Photos while keeping automatic phone backup.$q$, $q$Privacy-conscious families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Homelab media server$q$, $q$Adding a self-hosted photo and video backup service to an existing homelab or NAS setup.$q$, $q$Homelab and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Private AI-powered photo search$q$, $q$Using facial recognition and semantic search on a personal photo library without uploading it to a cloud AI service.$q$, $q$Privacy-focused photographers and individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A (AGPL-3.0 license)$q$, NULL, $q$["Full feature set including AI facial recognition and semantic search","Unlimited users on your own server","iOS and Android backup apps included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$Optional Product Key$q$, $q$One-time donation$q$, $q$One-time, via FUTO$q$, NULL, $q$["Supports ongoing development","No additional features unlocked beyond the free version"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Immich began in February 2022 as a personal project by developer Alex Tran, built to replicate the convenience of Google Photos' automatic phone backup without requiring users to hand their entire photo library to a third-party account. It grew rapidly through community contributions on GitHub before joining FUTO, a foundation that funds independent open-source software, as a full-time funded project in May 2024.$q$, $q$The project reached a stable v2.0.0 release in October 2025, removing the long-standing warning that it was not yet safe for storing irreplaceable photos and committing to semantic versioning going forward. It has since become one of the fastest-growing self-hosted applications on GitHub, surpassing 100,000 stars by 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Immich's mobile apps for iOS and Android automatically back up camera-roll photos and videos to a user's own server in the background, mirroring the core convenience of Google Photos. Its machine-learning microservice runs facial recognition and CLIP-based semantic search entirely locally, letting users search for photos by natural-language description, such as a dog at the beach, without manual tagging.$q$, $q$Additional features include shared albums for families, support for external photo libraries and existing folder structures, RAW and Live Photo support, a map view generated from photo geolocation data, and duplicate detection, all managed through an administrator panel that supports multiple user accounts on a single self-hosted server.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Immich has no subscription tiers and no feature paywall; every capability, including AI facial recognition and semantic search, is free under its AGPL-3.0 open-source license. Costs come entirely from self-hosting, which the community estimates at roughly $300 to $500 for a one-time home server setup plus a small ongoing electricity cost.$q$, $q$FUTO, the foundation funding Immich's development, sells an optional one-time product key purely as a way to support the project financially; purchasing it does not unlock any feature that is unavailable in the free, fully open-source version, keeping the software equally capable for every user.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
