INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a6a9fcd4-559e-4221-972d-3f4084fc1dc5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Disposable inbox alias generation$q$, $q$Creates unique, randomly-addressed email aliases that forward or store mail without exposing a user's real address.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Per-alias enable and disable$q$, $q$Lets users turn off or delete individual aliases that start receiving spam without affecting others.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Self-hosted Django and PostgreSQL stack$q$, $q$Runs as a standard, self-hostable Django web application backed by PostgreSQL.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$AGPL-3.0 open-source codebase$q$, $q$Full source code is available to audit, fork and modify under copyleft terms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Community-maintained on Codeberg$q$, $q$Development continues on Codeberg with the maintainer accepting community pull requests.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Privacy-first data handling$q$, $q$The project's shutdown of its own hosted instance included deleting associated databases and backups rather than retaining user data.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Fully open source and self-hostable under AGPL-3.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Strong privacy-first design philosophy, including data deletion on shutdown$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$AGPL license guarantees the code stays open even in hosted derivatives$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$No cost beyond your own server to run an instance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Development continues actively on Codeberg despite the original hosted service closing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$The original public hosted instance at inboxen.org has shut down, so there is no ready-to-use hosted option$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Requires real self-hosting skills in Python, Django, PostgreSQL and server administration$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$No official mobile apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Smaller community and support base than commercial alias services like SimpleLogin$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Documentation is developer-oriented rather than consumer-friendly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Is Inboxen still available as a hosted service?$q$, $q$No, the original public instance at inboxen.org has been shut down; the project's open-source code remains available for anyone to deploy their own self-hosted instance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Is Inboxen free?$q$, $q$Yes, Inboxen's source code is entirely free and open source under the AGPL-3.0 license, with no license fee to self-host it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$What technology is Inboxen built with?$q$, $q$Inboxen is built with Python and the Django web framework, using PostgreSQL as its database, with HTML, JavaScript and SCSS on the front end.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Can I self-host Inboxen?$q$, $q$Yes, the full codebase needed to run your own Inboxen instance is maintained on Codeberg, requiring Git, Python, PostgreSQL, Node.js and GNU Make to set up.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$What license is Inboxen released under?$q$, $q$Inboxen is released under the GNU Affero General Public License v3.0 (AGPL-3.0).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$What are alternatives to Inboxen?$q$, $q$Hosted commercial alias services such as SimpleLogin, addy.io (formerly AnonAddy) and Firefox Relay offer similar disposable email aliasing without requiring self-hosting.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Self-hosted disposable email aliasing$q$, $q$Deploying a private instance to generate disposable aliases for website and service signups.$q$, $q$Privacy-conscious developers and self-hosters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Evaluating open-source alias infrastructure$q$, $q$Reviewing or forking an AGPL-licensed Django codebase as a reference for building similar privacy tooling.$q$, $q$Software teams and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Contributing to an open-source privacy project$q$, $q$Submitting pull requests or patches to the actively maintained Codeberg repository.$q$, $q$Open-source contributors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A (AGPL-3.0 license)$q$, NULL, $q$["Full source code available on Codeberg","Unlimited aliases on your own server","Complete control over data and retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$Public Hosted Instance$q$, $q$Not available$q$, $q$N/A$q$, NULL, $q$["The original inboxen.org public instance has been discontinued","Self-hosting is now the only way to run Inboxen"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Inboxen is an open-source project for generating disposable email inbox aliases, built with Python, Django and PostgreSQL and released under the AGPL-3.0 license. Rather than being run by a company, it exists as a community-maintained codebase that anyone can inspect, modify and self-host.$q$, $q$The project originally operated a public reference instance at inboxen.org so people could try disposable aliasing without running their own server, but that hosted instance has since been shut down, with the site displaying a closure notice and associated user data being deleted. The source code itself remains active and available for self-hosting, with the repository now maintained on Codeberg.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Inboxen generates unique, randomly-addressed email aliases that a user can hand out instead of their real address when signing up for websites or services. Mail sent to an alias is received and stored or forwarded through the user's own Inboxen instance, and individual aliases can be disabled or deleted if they start attracting spam, without ever exposing the underlying real address.$q$, $q$Because it is a self-hosted Django application, Inboxen gives operators full control over their data and infrastructure, including database backups, retention policies and server configuration, in contrast to trusting a third-party company to manage that data on their behalf.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Inboxen carries no license fee and has never been sold as a paid product; the AGPL-3.0-licensed source code is free to download, modify and deploy. The only cost involved is the infrastructure needed to self-host an instance, such as a small VPS or home server capable of running Python, Django and PostgreSQL.$q$, $q$With the original public inboxen.org instance now shut down, there is currently no ready-made hosted option to sign up for; anyone wanting to use Inboxen today needs to deploy and maintain their own instance from the Codeberg repository, or consider a hosted commercial alternative such as SimpleLogin or addy.io instead.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1dea1981-a33c-4b6f-bacd-a384dacee7f2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
