-- ── ILIAS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hosted learning management system from Germany used by universities, schools and companies.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1997, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Cologne, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$ILIAS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$ILIAS review 2026: this free, self-hosted, GPL-licensed learning management system from Germany, its features, hosting costs and Moodle comparison.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ILIAS, an acronym for Integriertes Lern-, Informations- und Arbeitskooperations-System (German for Integrated Learning, Information and Work Cooperation System), is a free, open-source, self-hosted learning management system originally developed at the University of Cologne. A prototype was built starting in late 1997 under the VIRTUS project, initiated and organized by Professor Wolfgang Leidhold at the university's Faculty of Management, Economics and Social Sciences, and ILIAS version 1 launched on November 2, 1998 for use within that faculty. As interest grew from other universities, the project team released ILIAS as open-source software under the GNU General Public License in 2000, and between 2002 and 2004 the platform was rebuilt from scratch as ILIAS 3, becoming, in 2004, the first open-source LMS to reach full SCORM 1.2 compliance. Rather than being a venture-backed company, ILIAS is governed and maintained by the German nonprofit association ILIAS open source e-Learning e.V., headquartered in Cologne, which coordinates a global developer community, more than 90 institutional society members, and roughly 17 certified service and hosting providers. Technical architecture: ILIAS is written in PHP and runs on any server stack supporting PHP and a MySQL-compatible database; because it is self-hosted rather than SaaS, institutions install and operate it on their own infrastructure or through a certified partner rather than depending on a single vendor's cloud. Its feature set spans learning content management with SCORM 1.2 and SCORM 2004 compliant course packages and authoring tools, an assessment and testing engine supporting question pools and randomized or timed exams, collaboration tools including forums, wikis, blogs, chat and group workspaces, a course and learning-object repository, calendar and messaging, e-portfolio functionality, certificate generation, and detailed learning analytics and reporting. Role-based access control supports large multi-tenant deployments, with installations reported to scale from small groups of under 100 users up to systems serving well over 100,000 users, which is why it is widely adopted across German-speaking higher education and increasingly in other European countries. Pricing: ILIAS carries no license fee under the GPL and is free to download, install, modify and redistribute. The real costs institutions incur are for self-hosting infrastructure, or for contracting one of the ILIAS Society's certified service providers for managed hosting, customization, migration and training, plus an optional and comparatively inexpensive ILIAS Society membership fee for organizations that want a direct voice in the project's governance and roadmap. Target audience: public and private universities, vocational schools and K-12 institutions, and enterprises that need a self-hosted, GDPR-friendly LMS with full control over their data rather than a third-party SaaS provider. Named competitors and alternatives include Moodle (the most widely used open-source LMS globally, with a larger third-party plugin ecosystem), Canvas LMS by Instructure (a modern commercial SaaS product), Blackboard Learn (a legacy commercial enterprise LMS), and corporate-training-focused platforms like TalentLMS and Docebo. ILIAS differentiates itself from Moodle primarily through its strong built-in assessment and testing engine, its German data-protection heritage, and deep institutional adoption inside German and Austrian public education systems, while Moodle offers a broader international plugin and theming ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bc4665f4-feb7-4c9e-a25a-245306d04d1f';

