-- ── Immich ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hosted photo and video backup platform with AI facial recognition and search, a Google Photos alternative.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Immich Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Immich review 2026: this open-source, self-hosted Google Photos alternative with AI facial recognition, semantic search, mobile backup and setup costs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Immich is a free, open-source, self-hosted photo and video backup and management platform designed as a privacy-respecting alternative to Google Photos. The project was started in February 2022 by developer Alex Tran as a personal side project, driven by wanting the convenience of automatic phone photo backup without handing an entire photo library over to a third-party cloud account. It grew organically on GitHub through community contributions, and in May 2024 it joined FUTO, a foundation that funds and incubates independent, user-respecting software projects, as a funded, full-time effort, which allowed Alex Tran and a small core team to work on it professionally while keeping the codebase fully open source. By 2026 the project had become one of the fastest-growing self-hosted applications on GitHub, surpassing 100,000 stars, and in October 2025 it reached a stable v2.0.0 release, at which point the long-standing warning that the software was not yet safe for storing irreplaceable photos was removed, with the project committing to semantic versioning and limiting breaking changes to major version releases going forward. Technical architecture: Immich is deployed via Docker Compose as a set of containerized services, including a NestJS/Node.js backend server, a web frontend, a PostgreSQL database using the pgvector extension to store machine-learning embeddings, Redis for caching and job queues, and a separate machine-learning microservice that handles facial recognition and CLIP-based semantic image search, all running locally rather than calling external AI APIs. Native mobile apps for iOS and Android handle automatic background upload of camera-roll photos and videos to the user's own server. The project is licensed under the GNU Affero General Public License v3.0 (AGPL-3.0). Feature set includes automatic background mobile backup, facial recognition that groups photos by person, natural-language semantic search that lets users find images by describing their contents rather than manual tagging, object and scene detection, shared albums and libraries for families, support for external photo libraries and existing folder structures, RAW and Live Photo support, a map view built from photo geolocation data, duplicate photo detection, and an administrator panel for managing multiple user accounts on a single server. Pricing: Immich has no paid subscription tier and no feature paywall of any kind; every feature, including AI facial recognition and semantic search, is free under the AGPL-3.0 license. The only real-world cost is the hardware and hosting needed to self-host it, which the self-hosting community estimates at roughly $300 to $500 for a one-time home server, such as a mini PC or NAS, plus a few dollars a month in electricity, or the ongoing cost of a cloud VM if hosted remotely. FUTO also sells an optional one-time product key purely to fund development, which unlocks nothing that the free, fully open-source version already provides. Target audience: privacy-conscious individuals and families wanting to leave Google Photos or Apple iCloud Photos, homelab and self-hosting enthusiasts, and technically capable users comfortable running Docker on their own hardware or a rented server. Named competitors and alternatives include Google Photos and Apple iCloud Photos, the mainstream cloud incumbents Immich is explicitly positioned against, as well as other self-hosted photo-management projects like PhotoPrism and Nextcloud Memories, and paid cloud backup services such as IDrive or Backblaze for raw file backup without photo-specific AI features. Immich differentiates itself through close feature parity with Google Photos' mobile backup experience, a fast-moving open-source development pace, and free access to AI capabilities like face recognition and semantic search that are normally reserved for paid cloud products.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a6a9fcd4-559e-4221-972d-3f4084fc1dc5';

