-- ── Inboxen ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hostable project for generating disposable email inbox aliases; its original hosted instance has shut down.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Inboxen Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Inboxen review 2026: this open-source, self-hosted email alias project, its AGPL-3.0 license, current status and alternatives like SimpleLogin and addy.io.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Inboxen is an open-source email privacy project that lets users generate disposable, single-purpose email inbox aliases to shield a primary address from spam, tracking and data breaches, conceptually similar to hosted commercial services like SimpleLogin and addy.io. Unlike those companies, Inboxen was built and distributed as free, self-hostable software rather than a company-run product: its codebase is written in Python using the Django web framework with a PostgreSQL database, and its front end uses HTML, JavaScript and SCSS. The project is released under the GNU Affero General Public License v3.0 (AGPL-3.0), meaning anyone can inspect, modify, host and redistribute it, including any hosted-service modifications, under copyleft terms that keep derivative hosted versions open as well. Development is organized around a community of maintainers rather than a formal company, coordinated through a dedicated security contact for responsible vulnerability disclosure with GPG-encrypted reporting supported. The project originally operated its own public reference instance at inboxen.org, giving users a ready-to-use disposable-aliasing service without needing to run their own server; however, that hosted instance has since been shut down, with the site now displaying a notice confirming the service has closed and that associated databases and backups are being deleted, consistent with the project's privacy-first philosophy of not retaining user data indefinitely. The underlying codebase itself remains actively available for self-hosting: the repository has moved from GitHub to Codeberg, at codeberg.org/Inboxen/Inboxen, where the maintainer continues to accept pull requests and describes the repo as the complete system needed to set up an Inboxen instance. Running a self-hosted instance requires Git, Python with a virtual environment, PostgreSQL, Node.js and GNU Make, reflecting a fairly standard self-hosted Django application stack aimed at technically capable users rather than a plug-and-play consumer product. Conceptually, the core feature is generating an arbitrary number of unique, randomly-addressed inboxes, or aliases, that receive and store or forward mail sent to them, letting a user hand out a disposable address per website or service signup and then disable or delete individual aliases if they start attracting spam, all without exposing their real email address to any of those third parties. Because Inboxen is a general-purpose, community-maintained open-source project rather than a venture-backed company, it has no formal founding date, headquarters, employee count or funding history in the way a commercial startup would; it exists purely as a codebase that anyone can deploy. Target audience: privacy-conscious individuals and developers who are comfortable deploying and maintaining their own Django and PostgreSQL application and who want full control over a disposable email-alias system rather than trusting a third-party host, as well as researchers or contributors forking the codebase for similar privacy tooling. Named competitors and alternatives include hosted commercial alias services such as SimpleLogin, addy.io (formerly AnonAddy), and Firefox Relay, all of which offer managed disposable or alias email without requiring any self-hosting, as well as other open-source, self-hostable alternatives in the email-privacy space. Inboxen differentiates itself by being fully open source and self-hostable under AGPL-3.0 with no company or hosted product standing behind it, which offers maximum control and privacy for technical users but now requires them to run and maintain their own infrastructure, since the original public inboxen.org service is no longer operating.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1dea1981-a33c-4b6f-bacd-a384dacee7f2';

